import{_ as n,c as a,o as s,a as t}from"./app.1e429f93.js";const v='{"title":"Custom Validators","description":"","frontmatter":{},"headers":[{"level":2,"title":"Simple example","slug":"simple-example"},{"level":2,"title":"Optional validator","slug":"optional-validator"},{"level":2,"title":"Extra parameters","slug":"extra-parameters"},{"level":2,"title":"Passing extra properties to validators","slug":"passing-extra-properties-to-validators"},{"level":3,"title":"Passing extra reactive properties","slug":"passing-extra-reactive-properties"},{"level":2,"title":"Accessing property parent object","slug":"accessing-property-parent-object"},{"level":2,"title":"Accessing component instance from validator","slug":"accessing-component-instance-from-validator"},{"level":2,"title":"regex based validator","slug":"regex-based-validator"},{"level":2,"title":"Custom error messages","slug":"custom-error-messages"},{"level":2,"title":"Async validators","slug":"async-validators"},{"level":3,"title":"Async validators with extra reactive dependencies","slug":"async-validators-with-extra-reactive-dependencies"},{"level":3,"title":"Watching multiple extra values","slug":"watching-multiple-extra-values"},{"level":3,"title":"Passing a reactive property","slug":"passing-a-reactive-property"},{"level":2,"title":"forEach helper","slug":"foreach-helper"},{"level":2,"title":"List of helpers","slug":"list-of-helpers"}],"relativePath":"custom_validators.md","lastUpdated":1777558301323}',e={},p=t(`<h1 id="custom-validators" tabindex="-1">Custom Validators <a class="header-anchor" href="#custom-validators" aria-hidden="true">#</a></h1><p>You can easily write custom validators and combine them with builtin ones, as those are just a simple predicate functions.</p><h2 id="simple-example" tabindex="-1">Simple example <a class="header-anchor" href="#simple-example" aria-hidden="true">#</a></h2><p>Suppose you want a validator that checks if a string contains the word <code>cool</code> in it. You can write a plain JavaScript function to check that:</p><div class="language-js"><pre><code><span class="token keyword">const</span> <span class="token function-variable function">mustBeCool</span> <span class="token operator">=</span> <span class="token punctuation">(</span><span class="token parameter">value</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> value<span class="token punctuation">.</span><span class="token function">includes</span><span class="token punctuation">(</span><span class="token string">&#39;cool&#39;</span><span class="token punctuation">)</span>
</code></pre></div><p>The second part is actually applying your validator. You can do it exactly the same way as with builtin ones.</p><div class="language-js"><pre><code><span class="token keyword">export</span> <span class="token keyword">default</span> <span class="token punctuation">{</span>
  <span class="token function">data</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">return</span> <span class="token punctuation">{</span>
      <span class="token literal-property property">myField</span><span class="token operator">:</span> <span class="token string">&#39;cool&#39;</span>
    <span class="token punctuation">}</span>
  <span class="token punctuation">}</span><span class="token punctuation">,</span>
  <span class="token function">validations</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">return</span> <span class="token punctuation">{</span>
      <span class="token literal-property property">myField</span><span class="token operator">:</span> <span class="token punctuation">{</span>
        required<span class="token punctuation">,</span> mustBeCool
      <span class="token punctuation">}</span>
    <span class="token punctuation">}</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre></div><h2 id="optional-validator" tabindex="-1">Optional validator <a class="header-anchor" href="#optional-validator" aria-hidden="true">#</a></h2><p>The pattern presented above is often good enough, but this validator will always return <code>false</code> for empty inputs. This is not correct when your input is considered optional. For this reason, Vuelidate provides a <code>req</code> helper, which is a kinda stripped-down version of <code>required</code> validator. You can use it to make your validator behave well in presence of optional fields.</p><div class="language-js"><pre><code><span class="token keyword">import</span> <span class="token punctuation">{</span> helpers <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;@vuelidate/validators&#39;</span>

<span class="token keyword">const</span> <span class="token function-variable function">mustBeCool</span> <span class="token operator">=</span> <span class="token punctuation">(</span><span class="token parameter">value</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token operator">!</span>helpers<span class="token punctuation">.</span><span class="token function">req</span><span class="token punctuation">(</span>value<span class="token punctuation">)</span> <span class="token operator">||</span> value<span class="token punctuation">.</span><span class="token function">includes</span><span class="token punctuation">(</span><span class="token string">&#39;cool&#39;</span><span class="token punctuation">)</span>

<span class="token keyword">export</span> <span class="token keyword">default</span> <span class="token punctuation">{</span>
  <span class="token function">data</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token punctuation">,</span>
  <span class="token function">validations</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">return</span> <span class="token punctuation">{</span>
      <span class="token literal-property property">myField</span><span class="token operator">:</span> <span class="token punctuation">{</span>
        mustBeCool
      <span class="token punctuation">}</span>
    <span class="token punctuation">}</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre></div><h2 id="extra-parameters" tabindex="-1">Extra parameters <a class="header-anchor" href="#extra-parameters" aria-hidden="true">#</a></h2><p>If your validator needs to provide parameters, you can simply create a higher order function that returns the actual validator. This works great for simple validation cases:</p><div class="language-js"><pre><code><span class="token keyword">import</span> <span class="token punctuation">{</span> helpers <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;@vuelidate/validators&#39;</span>

<span class="token keyword">const</span> <span class="token function-variable function">contains</span> <span class="token operator">=</span> <span class="token punctuation">(</span><span class="token parameter">param</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">(</span><span class="token parameter">value</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span>
  <span class="token operator">!</span>helpers<span class="token punctuation">.</span><span class="token function">req</span><span class="token punctuation">(</span>value<span class="token punctuation">)</span> <span class="token operator">||</span> value<span class="token punctuation">.</span><span class="token function">includes</span><span class="token punctuation">(</span>param<span class="token punctuation">)</span>

<span class="token keyword">export</span> <span class="token keyword">default</span> <span class="token punctuation">{</span>
  <span class="token function">data</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token punctuation">,</span>
  <span class="token function">validations</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">return</span> <span class="token punctuation">{</span>
      <span class="token literal-property property">myField</span><span class="token operator">:</span> <span class="token punctuation">{</span>
        <span class="token literal-property property">mustBeCool</span><span class="token operator">:</span> <span class="token function">contains</span><span class="token punctuation">(</span><span class="token string">&#39;cool&#39;</span><span class="token punctuation">)</span>
      <span class="token punctuation">}</span>
    <span class="token punctuation">}</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre></div><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>If you need to pass reactive properties, you must use <code>withParams</code> helper, listed in <a href="#passing-extra-reactive-properties">Passing extra reactive properties</a></p></div><h2 id="passing-extra-properties-to-validators" tabindex="-1">Passing extra properties to validators <a class="header-anchor" href="#passing-extra-properties-to-validators" aria-hidden="true">#</a></h2><p>If you need to attach extra properties to your validation result, to display in error messages for example, you can use the <code>withParams</code> helper. It will attach a <code>$params</code> attribute on your validation result. Let&#39;s add a <code>type</code> property, so that we can later retrieve it.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p><code>$params</code> is reactive, which means you could add <code>computed</code> properties, <code>this</code> properties, <code>ref</code> or other, and they will update accordingly.</p></div><div class="language-js"><pre><code><span class="token keyword">import</span> <span class="token punctuation">{</span> helpers <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;@vuelidate/validators&#39;</span>

<span class="token keyword">const</span> mustBeCool <span class="token operator">=</span> helpers<span class="token punctuation">.</span><span class="token function">withParams</span><span class="token punctuation">(</span>
  <span class="token punctuation">{</span> <span class="token literal-property property">type</span><span class="token operator">:</span> <span class="token string">&#39;mustBeCool&#39;</span> <span class="token punctuation">}</span><span class="token punctuation">,</span>
  <span class="token punctuation">(</span><span class="token parameter">value</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token operator">!</span>helpers<span class="token punctuation">.</span><span class="token function">req</span><span class="token punctuation">(</span>value<span class="token punctuation">)</span> <span class="token operator">||</span> value<span class="token punctuation">.</span><span class="token function">includes</span><span class="token punctuation">(</span><span class="token string">&#39;cool&#39;</span><span class="token punctuation">)</span>
<span class="token punctuation">)</span>

<span class="token comment">// ...</span>

console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token keyword">this</span><span class="token punctuation">.</span>$v<span class="token punctuation">.</span>myField<span class="token punctuation">.</span>mustBeCool<span class="token punctuation">.</span>$params<span class="token punctuation">)</span>
<span class="token comment">// -&gt; { type: &#39;mustBeCool&#39; }</span>
</code></pre></div><h3 id="passing-extra-reactive-properties" tabindex="-1">Passing extra reactive properties <a class="header-anchor" href="#passing-extra-reactive-properties" aria-hidden="true">#</a></h3><p>The same behaviour extends to higher order validators, ones with extra parameters. You just must be careful to wrap the <strong>inner</strong> function with <code>withParams</code> call, as follows.</p><div class="language-js"><pre><code><span class="token keyword">import</span> <span class="token punctuation">{</span> helpers <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;@vuelidate/validators&#39;</span>

<span class="token keyword">const</span> <span class="token function-variable function">contains</span> <span class="token operator">=</span> <span class="token punctuation">(</span><span class="token parameter">param</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span>
  helpers<span class="token punctuation">.</span><span class="token function">withParams</span><span class="token punctuation">(</span>
    <span class="token punctuation">{</span> <span class="token literal-property property">type</span><span class="token operator">:</span> <span class="token string">&#39;contains&#39;</span><span class="token punctuation">,</span> <span class="token literal-property property">value</span><span class="token operator">:</span> param <span class="token punctuation">}</span><span class="token punctuation">,</span>
    <span class="token punctuation">(</span><span class="token parameter">value</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token operator">!</span>helpers<span class="token punctuation">.</span><span class="token function">req</span><span class="token punctuation">(</span>value<span class="token punctuation">)</span> <span class="token operator">||</span> value<span class="token punctuation">.</span><span class="token function">includes</span><span class="token punctuation">(</span>param<span class="token punctuation">)</span>
  <span class="token punctuation">)</span>

<span class="token keyword">export</span> <span class="token keyword">default</span> <span class="token punctuation">{</span>
  <span class="token function">validations</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">return</span> <span class="token punctuation">{</span>
      <span class="token literal-property property">myField</span><span class="token operator">:</span> <span class="token punctuation">{</span>
        <span class="token literal-property property">mustBeCool</span><span class="token operator">:</span> <span class="token function">contains</span><span class="token punctuation">(</span><span class="token string">&#39;cool&#39;</span><span class="token punctuation">)</span>
      <span class="token punctuation">}</span>
    <span class="token punctuation">}</span>
  <span class="token punctuation">}</span><span class="token punctuation">,</span>
  <span class="token function">created</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token keyword">this</span><span class="token punctuation">.</span>$v<span class="token punctuation">.</span>myField<span class="token punctuation">.</span>mustBeCool<span class="token punctuation">.</span>$params<span class="token punctuation">)</span>
    <span class="token comment">// -&gt; { type: &#39;contains&#39;, value: &#39;cool&#39; }</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre></div><h2 id="accessing-property-parent-object" tabindex="-1">Accessing property parent object <a class="header-anchor" href="#accessing-property-parent-object" aria-hidden="true">#</a></h2><p>If you need to create a validator, that directly needs access to a sibling property, you can use the second parameter of validators. The second parameter represents the object, surrounding the current property. It works for nested object properties, as well as top level properties, in which case it will just return the entire validated state.</p><div class="language-js"><pre><code><span class="token keyword">function</span> <span class="token function">otherFieldContainsMe</span> <span class="token punctuation">(</span><span class="token parameter">value<span class="token punctuation">,</span> siblings</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token keyword">return</span> siblings<span class="token punctuation">.</span>other<span class="token punctuation">.</span><span class="token function">contains</span><span class="token punctuation">(</span>value<span class="token punctuation">)</span>
<span class="token punctuation">}</span>

<span class="token keyword">const</span> v$ <span class="token operator">=</span> <span class="token function">useVuelidate</span><span class="token punctuation">(</span><span class="token punctuation">{</span>
  <span class="token literal-property property">foo</span><span class="token operator">:</span> <span class="token punctuation">{</span> otherFieldContainsMe <span class="token punctuation">}</span>
<span class="token punctuation">}</span><span class="token punctuation">,</span> <span class="token punctuation">{</span>
  <span class="token literal-property property">foo</span><span class="token operator">:</span> <span class="token string">&#39;foo&#39;</span><span class="token punctuation">,</span>
  <span class="token literal-property property">other</span><span class="token operator">:</span> <span class="token string">&#39;bar&#39;</span><span class="token punctuation">,</span>
<span class="token punctuation">}</span><span class="token punctuation">)</span>
</code></pre></div><h2 id="accessing-component-instance-from-validator" tabindex="-1">Accessing component instance from validator <a class="header-anchor" href="#accessing-component-instance-from-validator" aria-hidden="true">#</a></h2><p>In more complex cases when access to the whole model is necessary, you can make use of the function context (<code>this</code>), or the third parameter, to access any value on your component, this includes computed properties and data properties.</p><div class="language-js"><pre><code><span class="token comment">// both equivalent</span>
<span class="token keyword">const</span> <span class="token function-variable function">otherFieldContainsMe</span> <span class="token operator">=</span> <span class="token punctuation">(</span><span class="token parameter">value<span class="token punctuation">,</span> siblings<span class="token punctuation">,</span> vm</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>
  <span class="token keyword">return</span> vm<span class="token punctuation">.</span>other<span class="token punctuation">.</span>nested<span class="token punctuation">.</span>field<span class="token punctuation">.</span><span class="token function">contains</span><span class="token punctuation">(</span>value<span class="token punctuation">)</span>
<span class="token punctuation">}</span>

<span class="token keyword">function</span> <span class="token function">otherFieldContainsMe</span> <span class="token punctuation">(</span><span class="token parameter">value</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token keyword">return</span> <span class="token keyword">this</span><span class="token punctuation">.</span>other<span class="token punctuation">.</span>nested<span class="token punctuation">.</span>field<span class="token punctuation">.</span><span class="token function">contains</span><span class="token punctuation">(</span>value<span class="token punctuation">)</span>
<span class="token punctuation">}</span>
</code></pre></div><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>When using with Composition API, <code>vm</code> and <code>this</code> may not have your state on initial call. This is because the composition state has not yet been attached to the Vue instance yet. To work around this, you can either use the <code>$lazy</code> option, or use <code>await nextTick()</code> in your validator.</p></div><h2 id="regex-based-validator" tabindex="-1">regex based validator <a class="header-anchor" href="#regex-based-validator" aria-hidden="true">#</a></h2><p>Some validators can be easily expressed as <code>regex</code>. You can use a regex helper to quickly define full-fledged validator of this kind. This already includes handling optional fields and <code>$params</code>.</p><div class="language-js"><pre><code><span class="token keyword">import</span> <span class="token punctuation">{</span> helpers <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;vuelidate/lib/validators&#39;</span>

<span class="token keyword">const</span> alpha <span class="token operator">=</span> helpers<span class="token punctuation">.</span><span class="token function">regex</span><span class="token punctuation">(</span><span class="token regex"><span class="token regex-delimiter">/</span><span class="token regex-source language-regex">^[a-zA-Z]*$</span><span class="token regex-delimiter">/</span></span><span class="token punctuation">)</span>

<span class="token comment">// Also, you can pass multiple regex to validate a value.</span>
<span class="token keyword">const</span> alpha2 <span class="token operator">=</span> helpers<span class="token punctuation">.</span><span class="token function">regex</span><span class="token punctuation">(</span><span class="token regex"><span class="token regex-delimiter">/</span><span class="token regex-source language-regex">^[a-zA-Z]{3}</span><span class="token regex-delimiter">/</span></span><span class="token punctuation">,</span> <span class="token regex"><span class="token regex-delimiter">/</span><span class="token regex-source language-regex">\\d</span><span class="token regex-delimiter">/</span></span><span class="token punctuation">)</span>
</code></pre></div><h2 id="custom-error-messages" tabindex="-1">Custom error messages <a class="header-anchor" href="#custom-error-messages" aria-hidden="true">#</a></h2><p>While validators from the <code>@vuelidate/validators</code> package come with basic error messages, you may want to override them or define messages for your own validators. The best way to do this is via the <code>withMessage</code> helper.</p><p><code>withMessage</code> takes <code>message</code> as the first argument, and a validator as the second argument, returning a version of that validator with the customised message.</p><div class="language-js"><pre><code><span class="token keyword">import</span> <span class="token punctuation">{</span> required<span class="token punctuation">,</span> helpers <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;@vuelidate/validators&#39;</span>

<span class="token keyword">const</span> validations <span class="token operator">=</span> <span class="token punctuation">{</span>
  <span class="token literal-property property">name</span><span class="token operator">:</span> <span class="token punctuation">{</span>
    <span class="token literal-property property">required</span><span class="token operator">:</span> helpers<span class="token punctuation">.</span><span class="token function">withMessage</span><span class="token punctuation">(</span><span class="token string">&#39;This field cannot be empty&#39;</span><span class="token punctuation">,</span> required<span class="token punctuation">)</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre></div><p><code>$message</code> can also take a function that is reactive to changes in the validator state and model. The <code>$messages</code> function receives an object with the following properties:</p><table><thead><tr><th>Property</th><th></th></tr></thead><tbody><tr><td><code>$invalid</code></td><td>The valid state of the validator</td></tr><tr><td><code>$model</code></td><td>The value being validated</td></tr><tr><td><code>$params</code></td><td>Values of params in any validator created with the <code>withParams</code> helper</td></tr><tr><td><code>$pending</code></td><td>Whether an async validator has resolved yet</td></tr></tbody></table><div class="language-js"><pre><code><span class="token keyword">import</span> <span class="token punctuation">{</span> required<span class="token punctuation">,</span> helpers<span class="token punctuation">,</span> minLength <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;@vuelidate/validators&#39;</span>

<span class="token keyword">const</span> validations <span class="token operator">=</span> <span class="token punctuation">{</span>
  <span class="token literal-property property">name</span><span class="token operator">:</span> <span class="token punctuation">{</span>
    <span class="token literal-property property">minLength</span><span class="token operator">:</span> helpers<span class="token punctuation">.</span><span class="token function">withMessage</span><span class="token punctuation">(</span>
      <span class="token punctuation">(</span><span class="token parameter"><span class="token punctuation">{</span>
        $pending<span class="token punctuation">,</span>
        $invalid<span class="token punctuation">,</span>
        $params<span class="token punctuation">,</span>
        $model
      <span class="token punctuation">}</span></span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token template-string"><span class="token template-punctuation string">\`</span><span class="token string">This field has a value of &#39;</span><span class="token interpolation"><span class="token interpolation-punctuation punctuation">\${</span>$model<span class="token interpolation-punctuation punctuation">}</span></span><span class="token string">&#39; but must have a min length of </span><span class="token interpolation"><span class="token interpolation-punctuation punctuation">\${</span>$params<span class="token punctuation">.</span>min<span class="token interpolation-punctuation punctuation">}</span></span><span class="token string"> so it is </span><span class="token interpolation"><span class="token interpolation-punctuation punctuation">\${</span>$invalid <span class="token operator">?</span> <span class="token string">&#39;invalid&#39;</span> <span class="token operator">:</span> <span class="token string">&#39;valid&#39;</span><span class="token interpolation-punctuation punctuation">}</span></span><span class="token template-punctuation string">\`</span></span><span class="token punctuation">,</span>
      <span class="token function">minLength</span><span class="token punctuation">(</span><span class="token number">4</span><span class="token punctuation">)</span>
    <span class="token punctuation">)</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre></div><h2 id="async-validators" tabindex="-1">Async validators <a class="header-anchor" href="#async-validators" aria-hidden="true">#</a></h2><p>Async validators that return a Promise, need to be wrapped in the <code>withAsync</code> helper. This will tell Vuelidate to treat the validator in a special way, tracking pending status, storing response and more.</p><div class="language-js"><pre><code><span class="token keyword">import</span> <span class="token punctuation">{</span> helpers <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;@vuelidate/validators&#39;</span>

<span class="token keyword">const</span> <span class="token punctuation">{</span> withAsync <span class="token punctuation">}</span> <span class="token operator">=</span> helpers
<span class="token keyword">export</span> <span class="token keyword">default</span> <span class="token punctuation">{</span>
  <span class="token function">data</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">return</span> <span class="token punctuation">{</span> <span class="token literal-property property">foo</span><span class="token operator">:</span> <span class="token string">&#39;&#39;</span> <span class="token punctuation">}</span>
  <span class="token punctuation">}</span><span class="token punctuation">,</span>
  <span class="token literal-property property">validations</span><span class="token operator">:</span> <span class="token punctuation">{</span>
    <span class="token literal-property property">foo</span><span class="token operator">:</span> <span class="token punctuation">{</span> <span class="token literal-property property">asyncValidator</span><span class="token operator">:</span> <span class="token function">withAsync</span><span class="token punctuation">(</span>asyncValidator<span class="token punctuation">)</span> <span class="token punctuation">}</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre></div><h3 id="async-validators-with-extra-reactive-dependencies" tabindex="-1">Async validators with extra reactive dependencies <a class="header-anchor" href="#async-validators-with-extra-reactive-dependencies" aria-hidden="true">#</a></h3><p>When your async validator depends internally on other properties, you can pass those as a second parameter to the <code>withAsync</code> helper.</p><p>Such scenarios are common, when relying on some reactive data, different from the validated property.</p><div class="language-js"><pre><code><span class="token keyword">const</span> foo <span class="token operator">=</span> <span class="token function">ref</span><span class="token punctuation">(</span><span class="token string">&#39;&#39;</span><span class="token punctuation">)</span>

<span class="token keyword">function</span> <span class="token function">validator</span> <span class="token punctuation">(</span><span class="token parameter">value</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token keyword">if</span> <span class="token punctuation">(</span>foo<span class="token punctuation">.</span>value <span class="token operator">===</span> <span class="token string">&#39;foo&#39;</span><span class="token punctuation">)</span> <span class="token keyword">return</span> <span class="token boolean">false</span>
  <span class="token keyword">return</span> value <span class="token operator">===</span> <span class="token string">&#39;bar&#39;</span>
<span class="token punctuation">}</span>

<span class="token keyword">const</span> asyncValidator <span class="token operator">=</span> <span class="token function">withAsync</span><span class="token punctuation">(</span>validator<span class="token punctuation">,</span> foo<span class="token punctuation">)</span> <span class="token comment">// here we pass in the \`foo\` ref as an extra watch target.</span>

<span class="token keyword">const</span> validations <span class="token operator">=</span> <span class="token punctuation">{</span>
  <span class="token literal-property property">someProperty</span><span class="token operator">:</span> <span class="token punctuation">{</span> asyncValidator <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre></div><h3 id="watching-multiple-extra-values" tabindex="-1">Watching multiple extra values <a class="header-anchor" href="#watching-multiple-extra-values" aria-hidden="true">#</a></h3><p>You can pass multiple extra dependencies to track, by passing an array of refs to <code>withAsync</code>.</p><div class="language-js"><pre><code><span class="token keyword">const</span> foo <span class="token operator">=</span> <span class="token function">ref</span><span class="token punctuation">(</span><span class="token string">&#39;&#39;</span><span class="token punctuation">)</span>
<span class="token keyword">const</span> bar <span class="token operator">=</span> <span class="token function">ref</span><span class="token punctuation">(</span><span class="token boolean">false</span><span class="token punctuation">)</span>
<span class="token keyword">const</span> <span class="token function-variable function">validator</span> <span class="token operator">=</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token boolean">true</span>

<span class="token keyword">const</span> asyncValidator <span class="token operator">=</span> <span class="token function">withAsync</span><span class="token punctuation">(</span>validator<span class="token punctuation">,</span> <span class="token punctuation">[</span>foo<span class="token punctuation">,</span> bar<span class="token punctuation">]</span><span class="token punctuation">)</span> <span class="token comment">// here we pass in the \`foo\` and \`bar\` refs, as extra watch targets.</span>
</code></pre></div><h3 id="passing-a-reactive-property" tabindex="-1">Passing a reactive property <a class="header-anchor" href="#passing-a-reactive-property" aria-hidden="true">#</a></h3><p>To pass a <code>reactive</code> property, when using the Options or Composition APis, you can just pass a function returning the correct value, or a computed property, returning that value:</p><div class="language-js"><pre><code><span class="token keyword">const</span> store <span class="token operator">=</span> <span class="token function">reactive</span><span class="token punctuation">(</span><span class="token punctuation">{</span> <span class="token literal-property property">foo</span><span class="token operator">:</span> <span class="token string">&#39;&#39;</span> <span class="token punctuation">}</span><span class="token punctuation">)</span>

<span class="token comment">// when using Composition API</span>
<span class="token keyword">const</span> asyncValidator <span class="token operator">=</span> <span class="token function">withAsync</span><span class="token punctuation">(</span>validator<span class="token punctuation">,</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> store<span class="token punctuation">.</span>foo<span class="token punctuation">)</span>

<span class="token comment">// or a computed property</span>
<span class="token keyword">const</span> getter <span class="token operator">=</span> <span class="token function">computed</span><span class="token punctuation">(</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> store<span class="token punctuation">.</span>foo<span class="token punctuation">)</span>
<span class="token keyword">const</span> asyncValidator <span class="token operator">=</span> <span class="token function">withAsync</span><span class="token punctuation">(</span>validator<span class="token punctuation">,</span> getter<span class="token punctuation">)</span>

<span class="token comment">// when using Options API</span>
<span class="token keyword">export</span> <span class="token keyword">default</span> <span class="token punctuation">{</span>
  <span class="token function">validatons</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">return</span> <span class="token punctuation">{</span>
      <span class="token literal-property property">foo</span><span class="token operator">:</span> <span class="token punctuation">{</span>
        <span class="token literal-property property">validator</span><span class="token operator">:</span> <span class="token function">withAsync</span><span class="token punctuation">(</span>asyncValidator<span class="token punctuation">,</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token keyword">this</span><span class="token punctuation">.</span>store<span class="token punctuation">.</span>foo<span class="token punctuation">)</span>
      <span class="token punctuation">}</span>
    <span class="token punctuation">}</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre></div><h2 id="foreach-helper" tabindex="-1">forEach helper <a class="header-anchor" href="#foreach-helper" aria-hidden="true">#</a></h2><p>The <code>forEach</code> helper is added for cases where you might need a very simple collection validation, but don&#39;t want to go into defining new components. Please read <a href="./advanced_usage.html#validating-collections">Validating Collections</a> carefully, before using it.</p><div class="language-js"><pre><code><span class="token keyword">import</span> <span class="token punctuation">{</span> helpers <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;@vuelidate/validators&#39;</span>

<span class="token keyword">const</span> rules <span class="token operator">=</span> <span class="token punctuation">{</span>
  <span class="token literal-property property">collection</span><span class="token operator">:</span> <span class="token punctuation">{</span>
    <span class="token literal-property property">$each</span><span class="token operator">:</span> helpers<span class="token punctuation">.</span><span class="token function">forEach</span><span class="token punctuation">(</span><span class="token punctuation">{</span>
      <span class="token literal-property property">name</span><span class="token operator">:</span> <span class="token punctuation">{</span>
        required
      <span class="token punctuation">}</span>
    <span class="token punctuation">}</span><span class="token punctuation">)</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre></div><h2 id="list-of-helpers" tabindex="-1">List of helpers <a class="header-anchor" href="#list-of-helpers" aria-hidden="true">#</a></h2><p>This table contains all helpers that can be used to help you with writing your own validators. You can import them from validators library</p><div class="language-js"><pre><code><span class="token keyword">import</span> <span class="token punctuation">{</span> helpers <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;@vuelidate/validators&#39;</span>
</code></pre></div><table><thead><tr><th>Helper</th><th>Description</th></tr></thead><tbody><tr><td><code>withParams</code></td><td>Allows adding <code>$params</code> metadata to your validation function.</td></tr><tr><td><code>withMessage</code></td><td>Allows adding custom error messages to built-in or custom validators</td></tr><tr><td><code>withAsync</code></td><td>Specifies that a validator returns a promise.</td></tr><tr><td><code>forEach</code></td><td>Helper to migrate from old <code>$each</code> helper more easily.</td></tr><tr><td><code>req</code></td><td>Minimal version of <code>required</code> validator. Use it to make your validator accept optional fields</td></tr><tr><td><code>len</code></td><td>Get length of any kind value, whatever makes sense in the context. This can mean array length, string length, or number of keys on the object</td></tr><tr><td><code>regex</code></td><td>Useful for quick creation of regex based validators.</td></tr><tr><td><code>unwrap</code></td><td>Extract a value, from a ref, computed, or reactive property.</td></tr></tbody></table>`,58),o=[p];function c(l,r,i,u,k,d){return s(),a("div",null,o)}var y=n(e,[["render",c]]);export{v as __pageData,y as default};
